+    fn prepared_direct_simple_insert_expr_supported(expr: &Expr) -> bool {
+        match expr {
+            Expr::Literal(_, _) | Expr::Placeholder(_, _) => true,
+            Expr::Column(_, _) | Expr::Raise { .. } | Expr::Exists { .. } | Expr::Subquery(_, _) => {
+                false
+            }
+            Expr::BinaryOp { left, right, .. } => {
+                Self::prepared_direct_simple_insert_expr_supported(left)
+                    && Self::prepared_direct_simple_insert_expr_supported(right)
+            }
+            Expr::UnaryOp { expr: inner, .. }
+            | Expr::Cast { expr: inner, .. }
+            | Expr::Collate { expr: inner, .. }
+            | Expr::IsNull { expr: inner, .. } => {
+                Self::prepared_direct_simple_insert_expr_supported(inner)
+            }
+            Expr::Between {
+                expr: inner,
+                low,
+                high,
+                ..
+            } => {
+                Self::prepared_direct_simple_insert_expr_supported(inner)
+                    && Self::prepared_direct_simple_insert_expr_supported(low)
+                    && Self::prepared_direct_simple_insert_expr_supported(high)
+            }
+            Expr::In {
+                expr: inner, set, ..
+            } => {
+                Self::prepared_direct_simple_insert_expr_supported(inner)
+                    && match set {
+                        InSet::List(values) => values
+                            .iter()
+                            .all(Self::prepared_direct_simple_insert_expr_supported),
+                        InSet::Subquery(_) | InSet::Table(_) => false,
+                    }
+            }
+            Expr::Like {
+                expr: inner,
+                pattern,
+                escape,
+                ..
+            } => {
+                Self::prepared_direct_simple_insert_expr_supported(inner)
+                    && Self::prepared_direct_simple_insert_expr_supported(pattern)
+                    && escape
+                        .as_deref()
+                        .is_none_or(Self::prepared_direct_simple_insert_expr_supported)
+            }
+            Expr::Case {
+                operand,
+                whens,
+                else_expr,
+                ..
+            } => {
+                operand
+                    .as_deref()
+                    .is_none_or(Self::prepared_direct_simple_insert_expr_supported)
+                    && whens.iter().all(|(when_expr, then_expr)| {
+                        Self::prepared_direct_simple_insert_expr_supported(when_expr)
+                            && Self::prepared_direct_simple_insert_expr_supported(then_expr)
+                    })
+                    && else_expr
+                        .as_deref()
+                        .is_none_or(Self::prepared_direct_simple_insert_expr_supported)
+            }
+            Expr::FunctionCall {
+                args,
+                distinct,
+                order_by,
+                filter,
+                over,
+                ..
+            } => {
+                !*distinct
+                    && order_by.is_empty()
+                    && filter.is_none()
+                    && over.is_none()
+                    && match args {
+                        FunctionArgs::Star => true,
+                        FunctionArgs::List(arguments) => arguments
+                            .iter()
+                            .all(Self::prepared_direct_simple_insert_expr_supported),
+                    }
+            }
+            Expr::JsonAccess {
+                expr: inner, path, ..
+            } => {
+                Self::prepared_direct_simple_insert_expr_supported(inner)
+                    && Self::prepared_direct_simple_insert_expr_supported(path)
+            }
+            Expr::RowValue(_, _) => false,
+        }
+    }
